+
+/// Simplified SQLite format/printf implementation.
+/// Supports: %d, %f, %e, %g, %s, %q, %Q, %w, %%, %n (no-op).
+fn sqlite_format(fmt: &str, params: &[SqliteValue]) -> Result<String> {
+    let mut result = String::new();
+    let chars: Vec<char> = fmt.chars().collect();
+    let mut i = 0;
+    let mut param_idx = 0;
+
+    while i < chars.len() {
+        if chars[i] != '%' {
+            result.push(chars[i]);
+            i += 1;
+            continue;
+        }
+        i += 1;
+        if i >= chars.len() {
+            break;
+        }
+
+        // Parse flags
+        let mut left_align = false;
+        let mut show_sign = false;
+        let mut space_sign = false;
+        let mut zero_pad = false;
+        loop {
+            if i >= chars.len() {
+                break;
+            }
+            match chars[i] {
+                '-' => left_align = true,
+                '+' => show_sign = true,
+                ' ' => space_sign = true,
+                '0' => zero_pad = true,
+                _ => break,
+            }
+            i += 1;
+        }
+
+        // Parse width
+        let mut width = 0usize;
+        while i < chars.len() && chars[i].is_ascii_digit() {
+            width = width * 10 + (chars[i] as usize - '0' as usize);
+            i += 1;
+        }
+
+        // Parse precision
+        let mut precision = None;
+        if i < chars.len() && chars[i] == '.' {
+            i += 1;
+            let mut prec = 0usize;
+            while i < chars.len() && chars[i].is_ascii_digit() {
+                prec = prec * 10 + (chars[i] as usize - '0' as usize);
+                i += 1;
+            }
+            precision = Some(prec);
+        }
+
+        if i >= chars.len() {
+            break;
+        }
+
+        let spec = chars[i];
+        i += 1;
+
+        match spec {
+            '%' => result.push('%'),
+            'n' => {} // no-op (security: never writes to memory)
+            'd' | 'i' => {
+                let val = params.get(param_idx).map_or(0, SqliteValue::to_integer);
+                param_idx += 1;
+                let formatted =
+                    format_integer(val, width, left_align, show_sign, space_sign, zero_pad);
+                result.push_str(&formatted);
+            }
+            'f' => {
+                let val = params.get(param_idx).map_or(0.0, SqliteValue::to_float);
+                param_idx += 1;
+                let prec = precision.unwrap_or(6);
+                let formatted = format_float_f(
+                    val, prec, width, left_align, show_sign, space_sign, zero_pad,
+                );
+                result.push_str(&formatted);
+            }
+            'e' | 'E' => {
+                let val = params.get(param_idx).map_or(0.0, SqliteValue::to_float);
+                param_idx += 1;
+                let prec = precision.unwrap_or(6);
+                let formatted = if spec == 'e' {
+                    format!("{val:.prec$e}")
+                } else {
+                    format!("{val:.prec$E}")
+                };
+                result.push_str(&pad_string(&formatted, width, left_align));
+            }
+            'g' | 'G' => {
+                let val = params.get(param_idx).map_or(0.0, SqliteValue::to_float);
+                param_idx += 1;
+                let _prec = precision.unwrap_or(6);
+                // Use shorter of %f and %e
+                let formatted = format!("{val}");
+                result.push_str(&pad_string(&formatted, width, left_align));
+            }
+            's' | 'z' => {
+                let val = params
+                    .get(param_idx)
+                    .map(SqliteValue::to_text)
+                    .unwrap_or_default();
+                param_idx += 1;
+                let truncated = if let Some(prec) = precision {
+                    val.chars().take(prec).collect::<String>()
+                } else {
+                    val
+                };
+                result.push_str(&pad_string(&truncated, width, left_align));
+            }
+            'q' => {
+                // Single-quote escaping
+                let val = params
+                    .get(param_idx)
+                    .map(SqliteValue::to_text)
+                    .unwrap_or_default();
+                param_idx += 1;
+                let escaped = val.replace('\'', "''");
+                result.push_str(&escaped);
+            }
+            'Q' => {
+                // Like %q but wrapped in quotes, NULL -> "NULL"
+                let param = params.get(param_idx);
+                param_idx += 1;
+                match param {
+                    Some(SqliteValue::Null) | None => result.push_str("NULL"),
+                    Some(v) => {
+                        let val = v.to_text();
+                        let escaped = val.replace('\'', "''");
+                        result.push('\'');
+                        result.push_str(&escaped);
+                        result.push('\'');
+                    }
+                }
+            }
+            'w' => {
+                // Double-quote escaping for identifiers
+                let val = params
+                    .get(param_idx)
+                    .map(SqliteValue::to_text)
+                    .unwrap_or_default();
+                param_idx += 1;
+                let escaped = val.replace('"', "\"\"");
+                result.push('"');
+                result.push_str(&escaped);
+                result.push('"');
+            }
+            'c' => {
+                let val = params.get(param_idx).map_or(0, SqliteValue::to_integer);
+                param_idx += 1;
+                #[allow(clippy::cast_sign_loss)]
+                if let Some(c) = char::from_u32(val as u32) {
+                    result.push(c);
+                }
+            }
+            _ => {
+                // Unknown specifier: output literally
+                result.push('%');
+                result.push(spec);
+            }
+        }
+        // Suppress unused warnings
+        let _ = (left_align, show_sign, space_sign, zero_pad);
+    }
+    Ok(result)
+}
+
+fn format_integer(
+    val: i64,
+    width: usize,
+    left_align: bool,
+    show_sign: bool,
+    space_sign: bool,
+    zero_pad: bool,
+) -> String {
+    let sign = if val < 0 {
+        "-".to_owned()
+    } else if show_sign {
+        "+".to_owned()
+    } else if space_sign {
+        " ".to_owned()
+    } else {
+        String::new()
+    };
+    let digits = format!("{}", val.abs());
+    let body = format!("{sign}{digits}");
+    if body.len() >= width {
+        return body;
+    }
+    let pad = width - body.len();
+    if left_align {
+        format!("{body}{}", " ".repeat(pad))
+    } else if zero_pad {
+        format!("{sign}{}{digits}", "0".repeat(pad))
+    } else {
+        format!("{}{body}", " ".repeat(pad))
+    }
+}
+
+fn format_float_f(
+    val: f64,
+    prec: usize,
+    width: usize,
+    left_align: bool,
+    show_sign: bool,
+    space_sign: bool,
+    zero_pad: bool,
+) -> String {
+    let sign = if val < 0.0 {
+        "-".to_owned()
+    } else if show_sign {
+        "+".to_owned()
+    } else if space_sign {
+        " ".to_owned()
+    } else {
+        String::new()
+    };
+    let digits = format!("{:.prec$}", val.abs());
+    let body = format!("{sign}{digits}");
+    if body.len() >= width {
+        return body;
+    }
+    let pad = width - body.len();
+    if left_align {
+        format!("{body}{}", " ".repeat(pad))
+    } else if zero_pad {
+        format!("{sign}{}{digits}", "0".repeat(pad))
+    } else {
+        format!("{}{body}", " ".repeat(pad))
+    }
+}
+
+fn pad_string(s: &str, width: usize, left_align: bool) -> String {
+    if s.len() >= width {
+        return s.to_owned();
+    }
+    let pad = width - s.len();
+    if left_align {
+        format!("{s}{}", " ".repeat(pad))
+    } else {
+        format!("{}{s}", " ".repeat(pad))
+    }
+}
