+        if args.len() < 2 || args[0].is_null() || args[1].is_null() {
+            return Ok(SqliteValue::Null);
+        }
+        let fmt = args[0].to_text();
+        let rest = &args[1..];
+        match parse_args(rest) {
+            Some((jdn, _)) => Ok(SqliteValue::Text(format_strftime(&fmt, jdn))),
+            None => Ok(SqliteValue::Null),
+        }
+    }
