+        match &args[0] {
+            SqliteValue::Null => Ok(SqliteValue::Null),
+            SqliteValue::Integer(i) => Ok(SqliteValue::Integer(*i)),
+            other => {
+                let Some(x) = to_f64(other) else {
+                    return Ok(SqliteValue::Null);
+                };
+                Ok(wrap(x.trunc()))
+            }
+        }
+    }
+
+    fn num_args(&self) -> i32 {
+        1
+    }
+
+    fn name(&self) -> &str {
+        "trunc"
+    }
+}
